// src/components/Dashboard.js
import React from 'react';
import { useNavigate } from 'react-router-dom';

function Dashboard() {
  const navigate = useNavigate();

  // Get user role from localStorage
  const role = localStorage.getItem('role');
  const username = localStorage.getItem('username');

  // If no user is logged in (i.e., no username), redirect to login page
  if (!username) {
    navigate('/');
  }

  return (
    <div>
      <h2>Welcome to the Dashboard</h2>
      <p>Username: {username}</p>
      <p>Role: {role}</p>

      {role === 'admin' && <p>You have administrative privileges.</p>}
      {role === 'user' && <p>You have standard user privileges.</p>}

      {/* Additional content or functionality based on the role */}
    </div>
  );
}

export default Dashboard;
